  static List<MockTestQuestion> getQuestions(String level, String? topicKey) {
    final lvl = _levelKey(level);
    if (topicKey != null && data.containsKey(topicKey) && data[topicKey]!.containsKey(lvl)) {
      final pool = List<MockTestQuestion>.from(data[topicKey]![lvl]!);
      pool.shuffle();
      final count = _countForLevel(level);
      return pool.take(count).toList();
    }
    // All topics
    final pool = <MockTestQuestion>[];
    for (final t in data.values) {
      if (t.containsKey(lvl)) pool.addAll(t[lvl]!);
    }
    pool.shuffle();
    final count = _countForLevel(level);
    return pool.take(count).toList();
  }

  static String _levelKey(String level) {
    if (level == 'beginner') return 'basic';
    if (level == 'intermediate') return 'intermediate';
    return 'advanced';
  }

  static int _countForLevel(String level) {
    if (level == 'beginner') return 10;
    if (level == 'intermediate') return 20;
    return 30;
  }
}
